import AIAssistant from './components/AIAssistant';
import Footer from './components/Footer';
import AdminLogin from './components/AdminLogin';
import DashboardLayout from './components/admin/DashboardLayout';
import DashboardHome from './components/admin/DashboardHome';
import ProductManager from './components/admin/ProductManager';
import InventoryManager from './components/admin/InventoryManager';
import OrderManager from './components/admin/OrderManager';
import SalesHistory from './components/admin/SalesHistory';
import CustomerManager from './components/admin/CustomerManager';
import MpesaLogs from './components/admin/MpesaLogs';
import UserManager from './components/admin/UserManager';
import AuditLogs from './components/admin/AuditLogs';
import SettingsManager from './components/admin/SettingsManager';
import QuoteManager from './components/admin/QuoteManager';
import ReportsManager from './components/admin/ReportsManager';
import BranchManager from './components/admin/BranchManager';
import PosTerminal from './components/admin/PosTerminal';
import BlogManager from './components/admin/BlogManager';
import CmsManager from './components/admin/CmsManager';
import Profile from './components/admin/Profile';
import B2BPortal from './components/admin/B2BPortal';
import ShippingManager from './components/admin/ShippingManager';
import FinanceManager from './components/admin/FinanceManager';
import CategoryManager from './components/admin/CategoryManager';
import PartFinder from './components/PartFinder';
import Blog from './components/Blog';
import Contact from './components/Contact';
import About from './components/About';
import WarrantyPolicy from './components/WarrantyPolicy';
import Toast, { ToastType } from './components/Toast';
import SEO from './components/SEO';
import QuickView from './components/QuickView';
import { ViewState, Product, CartItem } from './types';
import { CheckCircle, MessageCircle } from 'lucide-react';
import ReactGA from "react-ga4";
import { apiClient, slugify } from './utils/apiClient';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('HOME');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isAiOpen, setIsAiOpen] = useState(false);

  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [activePostId, setActivePostId] = useState<string | null>(null);

  const [user, setUser] = useState<any>(null);
  const [token, setToken] = useState<string | null>(null);
  const [adminModule, setAdminModule] = useState('dashboard');
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  const handleRouting = async () => {
      const params = new URLSearchParams(window.location.search);
      const viewParam = params.get('view');
      const productParam = params.get('product');
      const postParam = params.get('post');

      if (productParam) {
          // Extract real ID from ID-slug format
          const realId = productParam.split('-')[0];
          try {
              if (!selectedProduct || selectedProduct.id !== realId) {
                  const res = await apiClient.get(`/products/${realId}`);
                  if (res.data) setSelectedProduct(res.data);
              }
          } catch (e) {
              console.error("Deep link product not found");
          }
      } else {
          if (selectedProduct) setSelectedProduct(null);
      }

      if (postParam) {
          const realPostId = postParam.split('-')[0];
          setActivePostId(realPostId);
          setView('BLOG');
      } else if (viewParam) {
          setView(viewParam as ViewState);
      } else if (!productParam && !postParam) {
          if (view !== 'CATALOG') setView('HOME');
      }
  };

  useEffect(() => {
      const initSettings = async () => {
          try {
              const res = await apiClient.get('/settings');
              const gaId = res.data.GOOGLE_ANALYTICS_ID;
              if (gaId) {
                  ReactGA.initialize(gaId);
                  ReactGA.send({ hitType: "pageview", page: window.location.pathname });
              }
          } catch (e) {}
      };
      initSettings();
      handleRouting();
      const storedToken = localStorage.getItem('masuma_auth_token');
      const storedUser = localStorage.getItem('masuma_user');
      if (storedToken && storedUser) {
          setToken(storedToken);
          setUser(JSON.parse(storedUser));
      }
      const storedCart = localStorage.getItem('masuma_cart');
      if (storedCart) setCart(JSON.parse(storedCart));
      window.addEventListener('popstate', handleRouting);
      return () => window.removeEventListener('popstate', handleRouting);
  }, []);

  const openProduct = (product: Product) => {
      setSelectedProduct(product);
      // Descriptive URL: ?product=ID-name-slug
      const newUrl = `${window.location.pathname}?product=${product.id}-${slugify(product.name)}`;
      window.history.pushState({ path: newUrl }, '', newUrl);
  };

  const closeProduct = () => {
      setSelectedProduct(null);
      const params = new URLSearchParams(window.location.search);
      params.delete('product');
      const newQuery = params.toString();
      const newUrl = window.location.pathname + (newQuery ? `?${newQuery}` : '');
      window.history.pushState({ path: newUrl }, '', newUrl);
  };

  useEffect(() => {
      if (typeof window !== 'undefined') {
          try {
            setTimeout(() => {
                ReactGA.send({ hitType: "pageview", page: window.location.pathname + window.location.search, title: document.title });
            }, 500);
          } catch(e) {}
      }
  }, [view, selectedProduct, activePostId]);

  useEffect(() => {
      localStorage.setItem('masuma_cart', JSON.stringify(cart));
  }, [cart]);

  const showToast = (message: string, type: ToastType = 'success') => {
      setToast({ message, type });
  };

  const addToCart = (product: Product, quantity = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item =>
          item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item
        );
      }
      return [...prev, { ...product, quantity }];
    });
    showToast(`Added ${product.name} to cart`);
    setIsCartOpen(true);
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, quantity: number) => {
      if (quantity < 1) return;
      setCart(prev => prev.map(item => item.id === id ? { ...item, quantity } : item));
  };

  const clearCart = () => {
      setCart([]);
      localStorage.removeItem('masuma_cart');
      showToast('Order placed successfully!');
  };

  const handleLoginSuccess = (userData: any, authToken: string) => {
      setUser(userData);
      setToken(authToken);
      localStorage.setItem('masuma_auth_token', authToken);
      localStorage.setItem('masuma_user', JSON.stringify(userData));
      setView('DASHBOARD');
  };

  const handleLogout = () => {
      setUser(null);
      setToken(null);
      localStorage.removeItem('masuma_auth_token');
      localStorage.removeItem('masuma_user');
      setView('HOME');
  };

  const renderContent = () => {
    if (view === 'DASHBOARD' && user) {
        const renderModule = () => {
            switch(adminModule) {
                case 'dashboard': return <DashboardHome onNavigate={setAdminModule} />;
                case 'products': return <ProductManager />;
                case 'inventory': return <InventoryManager />;
                case 'orders': return <OrderManager />;
                case 'sales_history': return <SalesHistory />;
                case 'customers': return <CustomerManager />;
                case 'mpesa': return <MpesaLogs />;
                case 'users': return <UserManager />;
                case 'audit': return <AuditLogs />;
                case 'settings': return <SettingsManager />;
                case 'quotes': return <QuoteManager />;
                case 'reports': return <ReportsManager />;
                case 'branches': return <BranchManager />;
                case 'pos': return <PosTerminal />;
                case 'blog': return <BlogManager />;
                case 'cms': return <CmsManager />;
                case 'profile': return <Profile />;
                case 'b2b': return <B2BPortal />;
                case 'shipping': return <ShippingManager />;
                case 'finance': return <FinanceManager />;
                case 'categories': return <CategoryManager />;
                default: return <DashboardHome onNavigate={setAdminModule} />;
            }
        };

        return (
            <DashboardLayout activeModule={adminModule} onNavigate={setAdminModule} onLogout={handleLogout}>
                <SEO title="Admin Dashboard" description="Masuma ERP System Internal Access" />
                {renderModule()}
            </DashboardLayout>
        );
    }

    if (view === 'LOGIN') {
        return (
            <>
                <SEO title="Staff Login" description="Secure access for Masuma Autoparts Staff" />
                <AdminLogin onLoginSuccess={handleLoginSuccess} onBack={() => setView('HOME')} />
            </>
        );
    }

    return (
        <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
            <Navbar 
                cartCount={cart.reduce((a, b) => a + b.quantity, 0)} 
                setView={setView} 
                toggleCart={() => setIsCartOpen(true)}
                toggleAi={() => setIsAiOpen(true)}
            />
            <main className="flex-grow">
            {view === 'HOME' && (
                <>
                <SEO title="Home" description="Official distributor of Masuma automotive parts in Kenya." />
                <Hero setView={setView} />
                <ProductList addToCart={addToCart} onProductClick={openProduct} />
                </>
            )}
            {view === 'CATALOG' && <ProductList addToCart={addToCart} onProductClick={openProduct} />}
            {view === 'PART_FINDER' && <PartFinder addToCart={addToCart} />}
            {view === 'BLOG' && <Blog addToCart={addToCart} initialPostId={activePostId} onProductClick={openProduct} />}
            {view === 'ABOUT' && <About setView={setView} />}
            {view === 'CONTACT' && <Contact />}
            {view === 'WARRANTY' && <WarrantyPolicy />}
            </main>
            <Footer setView={setView} />
            <CartDrawer isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} cartItems={cart} removeFromCart={removeFromCart} onCheckout={clearCart} updateQuantity={updateQuantity} />
            <AIAssistant isOpen={isAiOpen} onClose={() => setIsAiOpen(false)} />
            <QuickView product={selectedProduct} isOpen={!!selectedProduct} onClose={closeProduct} addToCart={addToCart} onSwitchProduct={openProduct} />
        </div>
    );
  };

  return (
    <>
        {renderContent()}
        {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { X, Check, AlertTriangle, Truck, MessageCircle, Plus, Minus, ArrowRight, Share2, Facebook, Twitter } from 'lucide-react';
import { Product } from '../types';
import QuoteModal from './QuoteModal';
import Price from './Price';
import { apiClient, slugify } from '../utils/apiClient';
import SEO from './SEO';

interface QuickViewProps {
  product: Product | null;
  isOpen: boolean;
  onClose: () => void;
  addToCart: (product: Product, quantity?: number) => void;
  onSwitchProduct?: (product: Product) => void;
}

const QuickView: React.FC<QuickViewProps> = ({ product, isOpen, onClose, addToCart, onSwitchProduct }) => {
  const [isQuoteModalOpen, setIsQuoteModalOpen] = useState(false);
  const [quantity, setQuantity] = useState(1);
  const [relatedProducts, setRelatedProducts] = useState<Product[]>([]);
  const [isLoadingRelated, setIsLoadingRelated] = useState(false);
  const [activeImage, setActiveImage] = useState('');
  const [gallery, setGallery] = useState<string[]>([]);

  useEffect(() => {
    if (isOpen && product) {
        setQuantity(1);
        const imgs = product.images && product.images.length > 0 ? product.images : [product.image];
        setGallery(imgs);
        setActiveImage(imgs[0]);
        fetchRelatedProducts(product);
    } 
  }, [isOpen, product]);

  const fetchRelatedProducts = async (currentProduct: Product) => {
      setIsLoadingRelated(true);
      try {
          const res = await apiClient.get(`/products?category=${currentProduct.category}&limit=10`);
          const allProducts = res.data.data || res.data || [];
          const filtered = allProducts.filter((p: Product) => p.id !== currentProduct.id);
          setRelatedProducts(filtered);
      } catch (error) {
          setRelatedProducts([]);
      } finally {
          setIsLoadingRelated(false);
      }
  };

  if (!isOpen || !product) return null;

  const handleQuantityChange = (delta: number) => {
    setQuantity(prev => Math.max(1, prev + delta));
  };

  const handleAddToCart = () => {
    addToCart(product, quantity);
    onClose();
  };

  const handleSwitch = (p: Product) => {
      if (onSwitchProduct) {
          const contentDiv = document.getElementById('quickview-content');
          if (contentDiv) contentDiv.scrollTop = 0;
          onSwitchProduct(p);
      }
  };

  // Improved Descriptive Share URL
  const shareUrl = `${window.location.origin}/?product=${product.id}-${slugify(product.name)}`;
  const shareText = `Check out this ${product.name} at Masuma Autoparts EA!`;

  const handleSocialShare = (platform: 'whatsapp' | 'facebook' | 'twitter') => {
      let url = '';
      switch (platform) {
          case 'whatsapp':
              url = `https://wa.me/?text=${encodeURIComponent(`${shareText} ${shareUrl}`)}`;
              break;
          case 'facebook':
              url = `https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(shareUrl)}`;
              break;
          case 'twitter':
              url = `https://twitter.com/intent/tweet?text=${encodeURIComponent(shareText)}&url=${encodeURIComponent(shareUrl)}`;
              break;
      }
      window.open(url, '_blank', 'width=600,height=400');
  };

  return (
    <>
      <SEO 
        title={product.name} 
        description={product.description.substring(0, 160)} 
        image={product.image}
        type="product"
        url={shareUrl}
      />
      <div className="fixed inset-0 z-[2000] flex items-center justify-center p-4 sm:p-6">
        <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={onClose}></div>
        <div className="relative bg-white w-full max-w-5xl rounded-lg shadow-2xl overflow-hidden flex flex-col max-h-[95vh] animate-scale-up">
          <button onClick={onClose} className="absolute top-3 right-3 z-50 p-2 bg-gray-100 hover:bg-masuma-orange hover:text-white rounded-full transition shadow-md border border-gray-200 group">
            <X size={24} className="text-gray-600 group-hover:text-white" />
          </button>
          <div id="quickview-content" className="flex-1 overflow-y-auto bg-white">
            <div className="flex flex-col md:flex-row border-b border-gray-200">
                <div className="w-full md:w-1/2 bg-white p-8 border-b md:border-b-0 md:border-r border-gray-100 flex flex-col">
                    <div className="flex-1 flex items-center justify-center relative min-h-[300px] mb-4">
                        <img src={activeImage} alt={product.name} className="max-h-[300px] md:max-h-[400px] w-full object-contain" />
                    </div>
                    {gallery.length > 1 && (
                        <div className="flex gap-2 overflow-x-auto pb-2 justify-center">
                            {gallery.map((img, idx) => (
                                <button key={idx} onClick={() => setActiveImage(img)} className={`w-16 h-16 border rounded overflow-hidden ${activeImage === img ? 'border-masuma-orange ring-1' : 'border-gray-200'}`}>
                                    <img src={img} className="w-full h-full object-cover" alt="" />
                                </button>
                            ))}
                        </div>
                    )}
                </div>
                <div className="w-full md:w-1/2 p-6 md:p-8">
                    <h2 className="text-2xl md:text-3xl font-bold text-masuma-dark font-display mb-4">{product.name}</h2>
                    <div className="mb-6">
                        <p className="text-3xl font-bold text-masuma-dark"><Price amount={product.price} /></p>
                        <p className="text-xs text-gray-400 mt-1 uppercase font-bold">SKU: {product.sku}</p>
                    </div>
                    <div className="mb-6">
                        <h3 className="text-xs font-bold text-gray-900 uppercase tracking-wider mb-2">Description</h3>
                        <p className="text-gray-600 text-sm leading-relaxed">{product.description}</p>
                    </div>
                    <div className="mb-6 flex items-center gap-3">
                        <span className="text-[10px] font-bold text-gray-400 uppercase">Share:</span>
                        <button onClick={() => handleSocialShare('whatsapp')} className="p-2 bg-green-100 text-green-600 rounded-full hover:bg-green-200 transition"><MessageCircle size={16} /></button>
                        <button onClick={() => handleSocialShare('facebook')} className="p-2 bg-blue-100 text-blue-600 rounded-full hover:bg-blue-200 transition"><Facebook size={16} /></button>
                        <button onClick={() => handleSocialShare('twitter')} className="p-2 bg-gray-100 text-black rounded-full hover:bg-gray-200 transition"><Twitter size={16} /></button>
                    </div>
                    <div className="flex flex-col sm:flex-row gap-4 pt-4 border-t border-gray-100">
                        <button onClick={handleAddToCart} disabled={!product.stock} className={`flex-1 py-3 px-4 font-bold uppercase tracking-widest text-xs transition flex items-center justify-center gap-2 ${product.stock ? 'bg-masuma-dark text-white hover:bg-masuma-orange' : 'bg-gray-200 text-gray-400'}`}>
                            {product.stock ? 'Add to Cart' : 'Sold Out'}
                        </button>
                        <button onClick={() => setIsQuoteModalOpen(true)} className="flex-1 py-3 px-4 font-bold uppercase tracking-widest text-xs border-2 border-masuma-dark hover:bg-masuma-dark hover:text-white">Quote</button>
                    </div>
                </div>
            </div>
          </div>
        </div>
      </div>
      <QuoteModal isOpen={isQuoteModalOpen} onClose={() => setIsQuoteModalOpen(false)} product={product} />
    </>
  );
};

export default QuickView;

import React, { useState, useEffect } from 'react';
import { ArrowLeft, Clock, Calendar, Share2, ArrowRight, BookOpen, Loader2, ChevronLeft, ChevronRight, Check } from 'lucide-react';
import { BlogPost, Product } from '../types';
import { apiClient, slugify } from '../utils/apiClient';
import SEO from './SEO';

interface BlogProps {
  addToCart: (product: Product) => void;
  initialPostId?: string | null;
  onProductClick?: (product: Product) => void;
}

const Blog: React.FC<BlogProps> = ({ addToCart, initialPostId, onProductClick }) => {
  const [selectedPost, setSelectedPost] = useState<BlogPost | null>(null);
  const [posts, setPosts] = useState<BlogPost[]>([]);
  const [relatedProducts, setRelatedProducts] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [pagination, setPagination] = useState({ page: 1, limit: 6, total: 0, pages: 1 });
  const [copied, setCopied] = useState(false);

  useEffect(() => {
      const init = async () => {
          setIsLoading(true);
          if (initialPostId) {
              try {
                  const res = await apiClient.get(`/blog/${initialPostId}`);
                  setSelectedPost(res.data);
              } catch (e) {
                  console.error("Deep link post not found");
              }
          }
          if (posts.length === 0) await fetchPosts(1);
          setIsLoading(false);
      };
      init();
  }, [initialPostId]);

  const fetchPosts = async (page: number) => {
      try {
          const res = await apiClient.get(`/blog?page=${page}&limit=${pagination.limit}`);
          if (res.data && res.data.data) {
              setPosts(res.data.data);
              setPagination(res.data.meta);
          }
      } catch (error) {}
  };

  const handleSelectPost = (e: React.MouseEvent, post: BlogPost) => {
      e.preventDefault();
      setSelectedPost(post);
      const newUrl = `${window.location.pathname}?post=${post.id}-${slugify(post.title)}`;
      window.history.pushState({ path: newUrl }, '', newUrl);
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleBack = () => {
      setSelectedPost(null);
      const cleanUrl = window.location.pathname;
      window.history.pushState({ path: cleanUrl }, '', cleanUrl);
  };

  const handleShare = async () => {
    if (!selectedPost) return;
    const shareUrl = `${window.location.origin}/?post=${selectedPost.id}-${slugify(selectedPost.title)}`;
    if (navigator.share) {
        try {
            await navigator.share({ title: selectedPost.title, url: shareUrl });
        } catch (err) {}
    } else {
        await navigator.clipboard.writeText(shareUrl);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    }
  };

  if (selectedPost) {
    return (
      <div className="animate-fade-in bg-white min-h-screen">
        <SEO title={selectedPost.title} description={selectedPost.excerpt} image={selectedPost.image} type="article" url={`${window.location.origin}/?post=${selectedPost.id}-${slugify(selectedPost.title)}`} />
        <div className="relative h-[50vh] w-full overflow-hidden">
          <div className="absolute inset-0 bg-masuma-dark/50 z-10"></div>
          <img src={selectedPost.image} alt={selectedPost.title} className="w-full h-full object-cover" />
          <div className="absolute inset-0 z-20 flex flex-col justify-end p-6 md:p-12 max-w-screen-2xl mx-auto">
            <button onClick={handleBack} className="absolute top-6 left-6 text-white bg-black/20 backdrop-blur-md px-4 py-2 rounded-full flex items-center gap-2 text-sm font-bold uppercase"><ArrowLeft size={16} /> Back</button>
            <h1 className="text-3xl md:text-5xl font-bold text-white font-display max-w-4xl mb-4">{selectedPost.title}</h1>
          </div>
        </div>
        <div className="max-w-4xl mx-auto px-4 py-12">
            <div className="prose prose-lg max-w-none text-gray-600">
                <div dangerouslySetInnerHTML={{ __html: selectedPost.content }} />
            </div>
            <div className="mt-12 pt-8 border-t flex justify-between items-center">
                <p className="font-bold text-sm uppercase">Share this article:</p>
                <button onClick={handleShare} className="flex items-center gap-2 px-4 py-2 bg-gray-100 rounded-full font-bold text-xs uppercase">
                    {copied ? <Check size={16} /> : <Share2 size={16} />} {copied ? 'Link Copied' : 'Share Link'}
                </button>
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-white min-h-screen">
      <SEO title="Blog & Insights" description="Automotive tips and news." />
      <div className="bg-masuma-dark text-white py-20 text-center">
         <h1 className="text-4xl md:text-6xl font-bold uppercase font-display mb-4">Expert Insights</h1>
         <div className="h-1 w-24 bg-masuma-orange mx-auto"></div>
      </div>
      <div className="max-w-7xl mx-auto px-4 py-16">
         {isLoading ? <Loader2 className="animate-spin text-masuma-orange mx-auto" size={48} /> : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {posts.map((post) => (
                   <a key={post.id} href={`/?post=${post.id}`} className="group bg-white border border-gray-200 hover:shadow-xl transition-all flex flex-col h-full" onClick={(e) => handleSelectPost(e, post)}>
                      <div className="h-56 overflow-hidden"><img src={post.image} className="w-full h-full object-cover group-hover:scale-105 transition duration-500" alt="" /></div>
                      <div className="p-6 flex-1 flex flex-col">
                         <h3 className="text-xl font-bold text-masuma-dark group-hover:text-masuma-orange transition-colors">{post.title}</h3>
                         <p className="text-gray-600 text-sm mt-4 line-clamp-3 leading-relaxed">{post.excerpt}</p>
                         <div className="mt-auto pt-6 flex items-center text-masuma-orange font-bold uppercase text-xs">Read Article <ArrowRight size={14} className="ml-2" /></div>
                      </div>
                   </a>
                ))}
            </div>
         )}
      </div>
    </div>
  );
};

export default Blog;

