import exchangeRoutes from './routes/exchange.routes';
import vehicleRoutes from './routes/vehicle.routes';
import uploadRoutes from './routes/upload.routes'; 
import financeRoutes from './routes/finance.routes';

const app = express();
app.set('trust proxy', 1);

AppDataSource.initialize()
  .then(() => {
    logger.info(`✅ Database connected: ${config.DB_NAME}`);
  })
  .catch((err) => {
    logger.error('❌ Database failed:', err);
  });

app.use(helmet({ contentSecurityPolicy: false }) as any); 
app.use(compression() as any); 
app.use(cors({ origin: (o, c) => c(null, true), credentials: true }) as any);
app.use(express.json() as any);
app.use(httpLogger as any);
app.use('/media', express.static(path.join(process.cwd(), 'media')) as any);

app.use('/api/auth', authRoutes as any);
app.use('/api/products', productRoutes as any); 
app.use('/api/inventory', inventoryRoutes as any);
app.use('/api/sales', salesRoutes as any);
app.use('/api/customers', customerRoutes as any);
app.use('/api/admin/stats', statsRoutes as any);
app.use('/api/orders', orderRoutes as any);
app.use('/api/mpesa', mpesaRoutes as any);
app.use('/api/blog', blogRoutes as any);
app.use('/api/users', userRoutes as any); 
app.use('/api/settings', settingsRoutes as any); 
app.use('/api/quotes', quoteRoutes as any);
app.use('/api/reports', reportRoutes as any);
app.use('/api/contact', contactRoutes as any); 
app.use('/api/branches', branchRoutes as any); 
app.use('/api/categories', categoryRoutes as any);
app.use('/api/health', healthRoutes as any);
app.use('/api/exchange-rates', exchangeRoutes as any);
app.use('/api/vehicles', vehicleRoutes as any);
app.use('/api/upload', uploadRoutes as any);
app.use('/api/finance', financeRoutes as any);

const cwd = process.cwd();
const possibleFrontendPaths = [
    path.join(cwd, '../dist'),
    path.join(cwd, 'dist'),
];
let frontendPath = possibleFrontendPaths.find(p => fs.existsSync(p));

// --- DYNAMIC META INJECTION ---
app.get('*', async (req: any, res: any, next: any) => {
    if (req.path.includes('.') && !req.path.endsWith('.html')) return next();
    if (req.path.startsWith('/api') || req.path.startsWith('/media')) return next();

    const indexPath = path.join(frontendPath || '', 'index.html');
    if (!fs.existsSync(indexPath)) return next();

    try {
        let html = fs.readFileSync(indexPath, 'utf8');

        // Handle Slugified Params: ID is everything before the first '-'
        const rawProduct = req.query.product;
        const rawPost = req.query.post;

        const productId = rawProduct ? rawProduct.split('-')[0] : null;
        const postId = rawPost ? rawPost.split('-')[0] : null;

        let metaTitle = 'Masuma Autoparts East Africa Limited';
        let metaDesc = 'Official distributor of Masuma automotive parts in Kenya. High-quality Japanese engineered parts.';
        let metaImage = 'https://masuma.africa/og-default.jpg';
        let metaUrl = `https://masuma.africa${req.url}`;

        if (productId) {
            const product = await AppDataSource.getRepository(Product).findOneBy({ id: productId });
            if (product) {
                metaTitle = `${product.name} | Masuma Autoparts EA`;
                metaDesc = product.description.substring(0, 160);
                metaImage = product.imageUrl || metaImage;
            }
        } else if (postId) {
            const post = await AppDataSource.getRepository(BlogPost).findOneBy({ id: postId });
            if (post) {
                metaTitle = `${post.title} | Masuma Blog`;
                metaDesc = post.excerpt.substring(0, 160);
                metaImage = post.image || metaImage;
            }
        }

        const injectTags = `
            <meta name="description" content="${metaDesc}">
            <meta property="og:title" content="${metaTitle}">
            <meta property="og:description" content="${metaDesc}">
            <meta property="og:image" content="${metaImage}">
            <meta property="og:url" content="${metaUrl}">
            <meta property="og:type" content="${postId ? 'article' : 'website'}">
            <meta name="twitter:card" content="summary_large_image">
            <meta name="twitter:title" content="${metaTitle}">
            <meta name="twitter:description" content="${metaDesc}">
            <meta name="twitter:image" content="${metaImage}">
        `;

        html = html.replace(/<title>.*?<\/title>/, `<title>${metaTitle}</title>`);
        html = html.replace('</head>', `${injectTags}</head>`);
        res.send(html);
    } catch (err) {
        next();
    }
});

app.use(express.static(frontendPath!) as any);
app.use(errorHandler as any);

const PORT = config.PORT;
app.listen(Number(PORT), '0.0.0.0', () => {
  logger.info(`🚀 Server running on port ${PORT}`);
});

