import { GoogleGenAI } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are 'MasumaBot', the official digital assistant for Masuma Autoparts East Africa Limited in Nairobi.
Your brand color is Orange (#E0621B). You are helpful, knowledgeable, and concise.

Your capabilities:
1. Advise on part compatibility for common Kenyan cars (Vitz, Demio, Fielder, Forester, Note, etc.).
2. Explain product features (e.g., "Why are ceramic brake pads better for Nairobi traffic?").
3. If a user asks for a specific part, ask them to provide the Chassis Number (VIN) so our team can check the live inventory.

Rules:
- Do not invent prices. If asked for a price, say: "Please check our live catalog on the website for the most up-to-date pricing."
- If a user asks about a specific part number, explain what it is generally (e.g. "That is an Oil Filter"), but direct them to the search bar for stock status.
- Be friendly and professional.
`;

export const sendMessageToGemini = async (history: {role: string, parts: {text: string}[]}[], message: string): Promise<string> => {
  try {
    // Initialization: Always use process.env.API_KEY directly as per guidelines
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    // Model selection: Using gemini-3-flash-preview for basic text tasks
    const model = 'gemini-3-flash-preview';

    const chat = ai.chats.create({
      model: model,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      },
      history: history, 
    });

    const response = await chat.sendMessage({
      message: message
    });

    // Extracting text: Use the .text property directly
    return response.text || "I'm having trouble accessing the network right now. Please try again.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    // Fail gracefully instead of crashing the app
    return "I'm having trouble connecting to the Masuma network right now. Please check your internet connection.";
  }
};

import { GoogleGenAI } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are 'MasumaBot', the official digital assistant for Masuma Autoparts East Africa Limited in Nairobi.
Your brand color is Orange (#E0621B). You are helpful, knowledgeable, and concise.

Your capabilities:
1. Advise on part compatibility for common Kenyan cars (Vitz, Demio, Fielder, Forester, Note, etc.).
2. Explain product features (e.g., "Why are ceramic brake pads better for Nairobi traffic?").
3. If a user asks for a specific part, ask them to provide the Chassis Number (VIN) so our team can check the live inventory.

Rules:
- Do not invent prices. If asked for a price, say: "Please check our live catalog on the website for the most up-to-date pricing."
- If a user asks about a specific part number, explain what it is generally (e.g. "That is an Oil Filter"), but direct them to the search bar for stock status.
- Be friendly and professional.
`;

export const sendMessageToGemini = async (history: {role: string, parts: {text: string}[]}[], message: string): Promise<string> => {
  try {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      console.error("Gemini API Key is missing from environment variables.");
      return "AI Configuration Error: Please ensure the API Key is set.";
    }

    // Initialize the AI client right before use
    const ai = new GoogleGenAI({ apiKey });

    // Construct the contents array including history and the new message
    // The history should be an array of { role, parts: [{ text }] }
    const contents = [
      ...history,
      { role: 'user', parts: [{ text: message }] }
    ];

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: contents,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
        topP: 0.95,
        topK: 40,
      },
    });

    // Extract text output using the .text property directly as per guidelines
    const responseText = response.text;

    if (!responseText) {
      throw new Error("Empty response from AI service");
    }

    return responseText;
  } catch (error: any) {
    console.error("Gemini API Error:", error);

    // Provide user-friendly feedback based on error types if possible
    if (error.message?.includes('API_KEY_INVALID')) {
      return "The AI service is currently unavailable due to an invalid configuration. Please contact Masuma Support.";
    }

    return "I'm having trouble connecting to the Masuma network right now. Please check your internet connection or try again in a moment.";
  }
};
